/**
 * 部首選擇頁面元件
 */
import { ALL_RADICALS } from '../data/gameEngine';

export default function RadicalSelect({
  lang, t,
  selectedRadicals,
  radicalSearch, setRadicalSearch,
  filteredCount,
  onToggleRadical, onSelectAll, onClearAll,
  onStartBattle, onBack,
}) {
  const visibleRadicals = ALL_RADICALS.filter(r =>
    !radicalSearch || r.includes(radicalSearch)
  );

  return (
    <>
      <div className="header" style={{ position: 'relative' }}>
        <button className="back-btn" onClick={onBack}>←</button>
        <h1>{lang === "zh" ? "選擇部首" : "Select Radicals"}</h1>
      </div>

      <div className="filter-count" dangerouslySetInnerHTML={{ __html: t.filterCount.replace("{{count}}", filteredCount) }} />

      <div className="radical-section">
        <div className="radical-header">
          <h4>
            {t.radicalTitle} <span className="count-badge">{selectedRadicals.size}/{ALL_RADICALS.length}</span>
          </h4>
          <span className="chip-actions">
            <button onClick={onSelectAll}>{t.equipAll}</button>
            <button onClick={onClearAll}>{t.unequipAll}</button>
          </span>
        </div>
        <input
          className="radical-search"
          placeholder={t.searchRadical}
          value={radicalSearch}
          onChange={e => setRadicalSearch(e.target.value)}
        />
        <div className="radical-chips" style={{ maxHeight: '50vh' }}>
          {visibleRadicals.map(r => (
            <span
              key={r}
              className={`radical-chip ${selectedRadicals.has(r) ? "on" : ""}`}
              onClick={() => onToggleRadical(r)}
            >
              {r}
            </span>
          ))}
        </div>
      </div>

      <button
        className="start-btn"
        onClick={onStartBattle}
        disabled={filteredCount === 0}
        style={{ marginTop: '16px' }}
      >
        ⚔️ {lang === "zh" ? `開始戰鬥！（${filteredCount} 字）` : `Start Battle! (${filteredCount} chars)`}
      </button>
    </>
  );
}
